--
-- Table structure for table `productos`
--

DROP TABLE IF EXISTS `productos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `productos` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `marca_id` bigint unsigned NOT NULL,
  `categoria_id` bigint unsigned NOT NULL,
  `nombre` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre_en` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nombre_fr` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `descripcion` text COLLATE utf8mb4_unicode_ci,
  `descripcion_en` text COLLATE utf8mb4_unicode_ci,
  `descripcion_fr` text COLLATE utf8mb4_unicode_ci,
  `publico` enum('hombre','mujer','infantil','unisex') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'hombre',
  `url_imagen_principal` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `galeria` json DEFAULT NULL,
  `precio` decimal(10,2) NOT NULL,
  `stock` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `productos_slug_unique` (`slug`),
  KEY `productos_marca_id_foreign` (`marca_id`),
  KEY `productos_categoria_id_foreign` (`categoria_id`),
  CONSTRAINT `productos_categoria_id_foreign` FOREIGN KEY (`categoria_id`) REFERENCES `categorias` (`id`) ON DELETE CASCADE,
  CONSTRAINT `productos_marca_id_foreign` FOREIGN KEY (`marca_id`) REFERENCES `marcas` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `productos`
--

LOCK TABLES `productos` WRITE;
/*!40000 ALTER TABLE `productos` DISABLE KEYS */;
INSERT INTO `productos` VALUES (1,1,1,'Zapatillas Nike Air Force 1 Clásicas Blancas','Zapatillas Nike Air Force 1 Clásicas Blancas (EN)','Zapatillas Nike Air Force 1 Clásicas Blancas (FR)','zapatillas-nike-air-force-1-cl-sicas-blancas','Vive la leyenda con las icónicas zapatillas Nike Air Force 1. Un diseño clásico e impecable completamente en blanco que combina con absolutamente cualquier conjunto de ropa de tu armario. Están confeccionadas con cuero genuino de alta durabilidad, costuras cosidas meticulosamente y la emblemática amortiguación Nike Air oculta en la suela gruesa, garantizando una comodidad insuperable en cada uno de tus pasos diarios. Perfectas para un estilo casual, urbano y atemporal.','English description for Zapatillas Nike Air Force 1 Clásicas Blancas. High quality and style.','Description en français pour Zapatillas Nike Air Force 1 Clásicas Blancas. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=800&q=80',NULL,119.99,45,'2026-04-09 14:56:59','2026-04-17 09:47:58'),(2,2,3,'Sudadera con Capucha Adidas Originals Trefoil','Sudadera con Capucha Adidas Originals Trefoil (EN)','Sudadera con Capucha Adidas Originals Trefoil (FR)','sudadera-con-capucha-adidas-originals-trefoil','Acurrúcate con estilo gracias a esta sudadera clásica de Adidas Originals. Destaca por exhibir el icónico y gigantesco logotipo del Trifolio (Trefoil) estampado en pleno pecho, convirtiéndose en el centro de todas las miradas. Fabricada con una rica mezcla de felpa y algodón de origen sostenible que acaricia la piel. Dispone de una práctica capucha ajustable con cordón grueso, además de un amplio bolsillo de canguro frontal para mantener las manos calientes en las frías mañanas de invierno urbano.','English description for Sudadera con Capucha Adidas Originals Trefoil. High quality and style.','Description en français pour Sudadera con Capucha Adidas Originals Trefoil. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1556821840-3a63f95609a7?w=800&q=80',NULL,90.00,30,'2026-04-09 14:56:59','2026-04-29 09:09:49'),(3,5,4,'Pantalón Vaquero Levi\'s 501 Original Fit','Pantalón Vaquero Levi\'s 501 Original Fit (EN)','Pantalón Vaquero Levi\'s 501 Original Fit (FR)','pantal-n-vaquero-levi-s-501-original-fit','La prenda que lo empezó absolutamente todo hace más de un siglo. Los genuinos e irremplazables vaqueros Levi\'s número 501 Original Fit representan el plano base a partir del cual todos los demás jeans han sido confeccionados en la historia moderna. Corte recto indiscutible en la cadera y el muslo, con la clásica y mundialmente conocida bragueta de botones remachados. Una tela denim de peso pesado, súper resistente que envejece con muchísima personalidad adaptándose a tu forma corporal única con el tiempo.','English description for Pantalón Vaquero Levi\'s 501 Original Fit. High quality and style.','Description en français pour Pantalón Vaquero Levi\'s 501 Original Fit. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1542272604-787c3835535d?w=800&q=80',NULL,89.00,80,'2026-04-09 14:56:59','2026-04-28 07:31:35'),(4,4,2,'Camiseta Zara Kids Estampado Dinosaurios','Camiseta Zara Kids Estampado Dinosaurios (EN)','Camiseta Zara Kids Estampado Dinosaurios (FR)','camiseta-zara-kids-estampado-dinosaurios','Despierta la imaginación prehistórica de los más pequeños con esta divertida camiseta de manga corta perteneciente a nuestra colección exclusiva Zara Kids. Presenta un vibrante, colorido y muy detallado estampado gráfico múltiple protagonizado por simpáticos dinosaurios repartidos por todo el torso de la prenda. Está cuidadosamente confeccionada utilizando punto de puro algodón cien por ciento orgánico certificado, completamente suave, ligero y totalmente transpirable. Cuello elástico que no agobia y corte súper libre.','English description for Camiseta Zara Kids Estampado Dinosaurios. High quality and style.','Description en français pour Camiseta Zara Kids Estampado Dinosaurios. Haute qualité et style.','infantil','https://images.unsplash.com/photo-1519241047957-be31d7379a5d?w=800&q=80',NULL,12.99,120,'2026-04-09 14:56:59','2026-04-17 09:47:58'),(5,3,1,'Zapatillas de Running Puma Velocity Nitro 2','Zapatillas de Running Puma Velocity Nitro 2 (EN)','Zapatillas de Running Puma Velocity Nitro 2 (FR)','zapatillas-de-running-puma-velocity-nitro-2','Experimenta la sensación real de flotar sobre el asfalto cuando sales a correr utilizando las zapatillas de alto rendimiento Puma Velocity Nitro 2. Este excepcional calzado deportivo neutro integra en toda la entresuela la innovadora espuma inyectada con gas nitrógeno patentada por la marca, garantizando de este modo un retorno de energía supremo, una amortiguación absurdamente suave y sobre todo una ligereza incomparable. El exterior de malla súper técnica envuelve cuidadosamente todo tu pie proporcionando increíble sujeción.','English description for Zapatillas de Running Puma Velocity Nitro 2. High quality and style.','Description en français pour Zapatillas de Running Puma Velocity Nitro 2. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=800&q=80',NULL,135.50,25,'2026-04-09 14:56:59','2026-04-28 07:31:35'),(6,7,1,'Zapatillas Vans Old Skool Classic Skate','Zapatillas Vans Old Skool Classic Skate (EN)','Zapatillas Vans Old Skool Classic Skate (FR)','zapatillas-vans-old-skool-classic-skate','Liderando ininterrumpidamente el estilo callejero urbano y abrazando por completo la genuina cultura de los deportes extremos de California encontramos a las maravillosas zapatillas Vans Old Skool. Primer calzado legendario en lucir públicamente la inconfundible franja lateral ondulada Sidestripe de la compañía. Se han fabricado minuciosamente con fuertes empeines mezclando tela de lona súper duradera e inserciones protectoras frontales de gamuza auténtica. Suela inyectada de caucho puro con la textura patentada Waffle.','English description for Zapatillas Vans Old Skool Classic Skate. High quality and style.','Description en français pour Zapatillas Vans Old Skool Classic Skate. Haute qualité et style.','mujer','https://images.unsplash.com/photo-1525966222134-fcfa99b8ae77?w=800&q=80',NULL,75.00,50,'2026-04-09 14:57:00','2026-04-28 07:31:35'),(7,4,6,'Vestido Zara Mujer Textura Midi Fluido','Vestido Zara Mujer Textura Midi Fluido (EN)','Vestido Zara Mujer Textura Midi Fluido (FR)','vestido-zara-mujer-textura-midi-fluido','Deslumbra elegantemente y acapara todas las atenciones apostando enormemente por este sofisticado y polivalente vestido de corte midi perteneciente al catálogo Zara Woman. Presenta una tela meticulosamente hilada que destaca sobre todo por un maravilloso tejido muy fluido y vaporoso con sutiles pero efectivas micro texturas. Dispone de un favorecedor escote central terminado delicadamente en forma de letra pico y delicados tirantes ultra finos que permiten lucir abiertamente los hombros durante largas cenas.','English description for Vestido Zara Mujer Textura Midi Fluido. High quality and style.','Description en français pour Vestido Zara Mujer Textura Midi Fluido. Haute qualité et style.','mujer','https://images.unsplash.com/photo-1595777457583-95e059d581b8?w=800&q=80',NULL,39.95,40,'2026-04-09 14:57:00','2026-04-17 09:47:58'),(8,1,5,'Chaqueta Deportiva Infantil Nike Windrunner','Chaqueta Deportiva Infantil Nike Windrunner (EN)','Chaqueta Deportiva Infantil Nike Windrunner (FR)','chaqueta-deportiva-infantil-nike-windrunner','Prepara meticulosamente y equipa plenamente a tus queridos hijos para poder afrontar sin ningún tipo de miedo aquellos días más fríos y húmedos gracias a esta indispensable chaqueta tipo cortavientos infantil modelo Windrunner lanzada por Nike. Cuenta históricamente con el mítico e inconfundible diseño principal en forma de V grande plasmado sobre el pecho. Increíblemente ligera, repelente del agua, dispone forro cómodo de malla interior. Cremallera frontal centralizada integral para ponérsela y quitársela.','English description for Chaqueta Deportiva Infantil Nike Windrunner. High quality and style.','Description en français pour Chaqueta Deportiva Infantil Nike Windrunner. Haute qualité et style.','infantil','https://images.unsplash.com/photo-1551028719-00167b16eac5?w=800&q=80',NULL,60.00,20,'2026-04-09 14:57:00','2026-04-29 09:05:11'),(9,6,1,'Zapatillas Deportivas New Balance 574 Core','Zapatillas Deportivas New Balance 574 Core (EN)','Zapatillas Deportivas New Balance 574 Core (FR)','zapatillas-deportivas-new-balance-574-core','Abraza la silueta inconfundible, inigualable y probablemente la más importante creada jamás en toda la extensísima historia cronológica de zapatillas New Balance, hablamos nada menos que del magistral modelo 574 Core. Este zapato icónico de aspecto retro fusiona exitosamente de manera experta el confort con unas líneas francamente limpias y atractivas. Empeine transpirable cuidadosamente mezclado de gamuza real premium con ventilación técnica de malla. Entresuela dotada de soporte especial de espuma EVA encapsulada.','English description for Zapatillas Deportivas New Balance 574 Core. High quality and style.','Description en français pour Zapatillas Deportivas New Balance 574 Core. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1539185441755-769473a23570?w=800&q=80',NULL,95.00,60,'2026-04-09 14:57:00','2026-04-28 07:31:36'),(10,2,7,'Gorra Trucker Unisex Adidas Originals','Gorra Trucker Unisex Adidas Originals (EN)','Gorra Trucker Unisex Adidas Originals (FR)','gorra-trucker-unisex-adidas-originals','Remata magistralmente tu conjunto de ropa de estilo puramente callejero y protege cómodamente frente al sol tus propios ojos introduciendo este espléndido accesorio. Es ni más ni menos que una sensacional gorra tipo trucker perteneciente íntegramente a Adidas Originals. Presenta majestuosamente un diseño superior en el que predomina un panel delantero muy robusto luciendo el característico e icónico logotipo sobredimensionado del trébol. Cuenta con toda la zona de la mitad posterior confeccionada en fina malla.','English description for Gorra Trucker Unisex Adidas Originals. High quality and style.','Description en français pour Gorra Trucker Unisex Adidas Originals. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1588850561407-ed78c282e89b?w=800&q=80',NULL,22.50,150,'2026-04-09 14:57:00','2026-04-28 07:31:36'),(11,1,1,'Zapatillas Nike Air Force 1 Clásicas Negras','Zapatillas Nike Air Force 1 Clásicas Negras (EN)','Zapatillas Nike Air Force 1 Clásicas Negras (FR)','zapatillas-nike-air-force-1-cl-sicas-negras','Desata absolutamente todo tu enorme potencial callejero vistiendo las legendarias e icónicas zapatillas Nike Air Force 1. Un diseño poderoso, agresivo y sumamente limpio enteramente tintado en un muy elegante y sobrio negro mate capaz de resistirse ferozmente a la abrumadora suciedad urbana. Confeccionadas partiendo de un resistente e inmaculado cuero premium liso, mantienen perfectamente oculta la sensacional tecnología especial Nike Air debajo del enorme grosor protector que nos aporta la gran suela de goma.','English description for Zapatillas Nike Air Force 1 Clásicas Negras. High quality and style.','Description en français pour Zapatillas Nike Air Force 1 Clásicas Negras. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=800&q=80',NULL,119.99,45,'2026-04-09 14:57:00','2026-04-17 09:47:58'),(12,2,3,'Sudadera con Capucha Adidas Infantil','Sudadera con Capucha Adidas Infantil (EN)','Sudadera con Capucha Adidas Infantil (FR)','sudadera-con-capucha-adidas-infantil','Mantén enormemente abrigados y repletos de comodidades modernas a tus pequeñines preferidos durante el gélido invierno confiando plenamente en esta pequeña gran iteración de nuestra fantástica sudadera más famosa y aplaudida. Una pieza innegociable nacida desde Adidas Originals luciendo el llamativo e inmenso trébol mítico frontal. Construida priorizando siempre emplear los algodones naturales completamente amigables con el medio. Su gigantesco bolsillo de estilo canguro mantendrá escondidos esos juguetes.','English description for Sudadera con Capucha Adidas Infantil. High quality and style.','Description en français pour Sudadera con Capucha Adidas Infantil. Haute qualité et style.','infantil','https://images.unsplash.com/photo-1556821840-3a63f95609a7?w=800&q=80',NULL,64.95,30,'2026-04-09 14:57:00','2026-04-17 09:47:58'),(13,4,2,'Camiseta Zara Kids Estampado Espacial','Camiseta Zara Kids Estampado Espacial (EN)','Camiseta Zara Kids Estampado Espacial (FR)','camiseta-zara-kids-estampado-espacial','Prepara las maletas e invita urgentemente a tu maravilloso hijo o fantástica hija a surcar de forma emocionante toda y cada una de las grandes estrellas del firmamento cósmico gracias a la deslumbrante magia inherente a esta interesantísima camiseta manga corta de Zara Kids. Su colorido y llamativo estampado espacial reluce repletito de hermosísimos planetas volanderos y rápidos cohetes. Fue minuciosamente elaborada escogiendo únicamente el mejor y más dócil poliéster fresco diseñado para correr y sudar.','English description for Camiseta Zara Kids Estampado Espacial. High quality and style.','Description en français pour Camiseta Zara Kids Estampado Espacial. Haute qualité et style.','infantil','https://images.unsplash.com/photo-1519241047957-be31d7379a5d?w=800&q=80',NULL,12.99,120,'2026-04-09 14:57:01','2026-04-17 09:47:58'),(14,3,1,'Zapatillas Puma Running Softride','Zapatillas Puma Running Softride (EN)','Zapatillas Puma Running Softride (FR)','zapatillas-puma-running-softride','Eleva enormemente la mismísima calidad de todas y cada una de tus maratones recurrentes utilizando la excelsa tecnología insertada cuidadosamente dentro de estas espectaculares zapatillas neutras provistas por la firma internacional Puma y bautizadas como Softride. Integran asombrosamente una capa inferior inmensa rellena enteramente de una espuma plástica súper reactiva patentada de altísimo confort y rendimiento superior para no tener ninguna fatiga plantar. Destacan notablemente por su peso.','English description for Zapatillas Puma Running Softride. High quality and style.','Description en français pour Zapatillas Puma Running Softride. Haute qualité et style.','hombre','https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=800&q=80',NULL,135.50,25,'2026-04-09 14:57:01','2026-04-28 07:31:36'),(15,6,1,'Zapatillas Deportivas New Balance 990','Zapatillas Deportivas New Balance 990 (EN)','Zapatillas Deportivas New Balance 990 (FR)','zapatillas-deportivas-new-balance-990','Asombra drásticamente al gigantesco mundo exterior presumiendo con soberbia de lucir libremente el estandarte que representa con abrumadora contundencia el linaje americano, esto es sin duda alguna calzar alegremente las New Balance modelo número 990 clásico indiscutible. Zapatillas míticas provistas orgullosamente de las líneas estéticas más atemporales disponibles hoy por hoy en el competitivo mercado actual del running. Destapan grandes y múltiples inserciones generosas compuestas con rica gamuza de cerdo.','English description for Zapatillas Deportivas New Balance 990. High quality and style.','Description en français pour Zapatillas Deportivas New Balance 990. Haute qualité et style.','mujer','https://images.unsplash.com/photo-1539185441755-769473a23570?w=800&q=80',NULL,95.00,60,'2026-04-09 14:57:01','2026-04-28 07:31:36'),(17,3,2,'Camiseta Básica de Algodón',NULL,NULL,'camiseta-basica-de-algodon','Manga corta transpirable, ideal para un look casual en verano.',NULL,NULL,'hombre','https://loremflickr.com/800/800/tshirt?lock=0',NULL,32.99,42,'2026-04-21 12:15:19','2026-04-21 12:15:19'),(18,7,2,'Camiseta Oversize Estampada',NULL,NULL,'camiseta-oversize-estampada','Corte holgado y estilo urbano con gráfico moderno.',NULL,NULL,'mujer','https://loremflickr.com/800/800/tshirt?lock=1',NU